/* Time operations for MC_DigitalCamSwitch */
extern TIME __CURRENT_TIME;
#define SECOND 1000000000
#define TIME_SECOND(t) (double)t / (double)SECOND
#define POSITIVE_TIME(t) ( (t) > 0 ? (t) : 0)
#define POSITION_IS_BETWEEN(p, p1, p2)     (p1 <= p2) ? (p >= p1 && p <= p2) : (p >= p2 && p <= p1)
/* Miscellaneous math operations for MC_DigitalCamSwitch */
inline int cmpf(double a, double b){
  double diff = a-b;
  int diffclass = fpclassify(diff);
  if(diffclass == FP_ZERO || diffclass == FP_SUBNORMAL) return 0;
  return signbit(diff) ? -1 : 1;
} 
inline double floormodf(double a, double b){
  if(signbit(a)) return fmod(a, b) + b;
  return fmod(a, b);
} 

