/* AXIS_REF pre-alocation */
AXIS_REF_s AXIS_REF_inst[MAX_AXIS_COUNT];

static unsigned int NextAllocatedAXIS_REF=0;
int __MK_Alloc_AXIS_REF(){
    if(NextAllocatedAXIS_REF<MAX_AXIS_COUNT){
        AXIS_REF_inst[NextAllocatedAXIS_REF]._Index = NextAllocatedAXIS_REF;
        return NextAllocatedAXIS_REF++;
    }else{
        return -1;
    }
}

axis_s* __MK_GetPublic_AXIS_REF(int index){
    if(index < NextAllocatedAXIS_REF){
        return &AXIS_REF_inst[index].public;
    }
    return NULL;
}
uint8_t __MK_CheckPublic_AXIS_REF(int index){
    axis_s* public = &AXIS_REF_inst[index].public;
    if(public && 1){
        return 1;
    }
    return 0;
}

